import React, { useState } from 'react';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState(Array(8).fill(''));
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const questions = [
    "Cuéntame un poco sobre ti.",
    "¿Por qué te interesa este puesto de desarrollador?",
    "¿Cuál consideras que ha sido tu mayor logro profesional?",
    "¿Cómo manejas situaciones de presión en el trabajo?",
    "¿Prefieres trabajar solo o en equipo? ¿Por qué?",
    "¿Dónde te ves profesionalmente dentro de 5 años?",
    "¿Por qué deberíamos contratarte para este puesto?",
    "¿Tienes experiencia previa relacionada con este tipo de trabajo?"
  ];

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const evaluarConJarvisLote = async () => {
    try {
      const response = await fetch("http://127.0.0.1:5000/evaluar-lote", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ preguntas: questions, respuestas: answers }),
      });

      if (!response.ok) throw new Error(`Error ${response.status}`);
      const data = await response.json();

      // Se espera que `data.evaluaciones` sea un array
      const evaluaciones = data.evaluaciones.map((evalua, i) => `Pregunta ${i + 1}: ✅ ${evalua}`);
      const informe = "📊 Evaluación automática de Jarvis:\n\n" + evaluaciones.join("\n\n");
      return informe;
    } catch (err) {
      console.error("❌ Error al evaluar con Jarvis:", err);
      throw err;
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    if (answers.some(answer => answer.trim() === '')) {
      setError('Por favor, responde todas las preguntas.');
      setLoading(false);
      return;
    }

    try {
      const result = await evaluarConJarvisLote();
      onSubmit(result, answers);
    } catch (err) {
      setError('❌ No se pudo conectar con la IA Jarvis.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {questions.map((question, i) => (
        <div key={i} style={{ marginBottom: '10px' }}>
          <label htmlFor={`answer-${i}`}>{question}</label><br />
          <textarea
            id={`answer-${i}`}
            rows={3}
            style={{ width: '100%', padding: '8px' }}
            onChange={(e) => handleInputChange(i, e.target.value)}
            value={answers[i]}
            required
            disabled={loading}
          />
        </div>
      ))}

      <button type="submit" disabled={loading} style={{ padding: '10px 20px' }}>
        {loading ? 'Evaluando con Jarvis...' : 'Evaluar con Jarvis'}
      </button>

      {error && <p style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

export default QuestionForm;
